from __future__ import annotations
from typing import Any


def build_answers(ctx: dict[str, Any]) -> dict[str, str]:
    return {'pathway_bottleneck': f"The largest descriptive stage is **{ctx['top_stage']['stage_label']}**, contributing {ctx['_pct'](ctx['top_stage']['share_of_complete_pathway_mean'])} of mean complete-pathway time; its median is {ctx['_fmt'](ctx['top_stage']['median_days'])} days and P90 {ctx['_fmt'](ctx['top_stage']['p90_days'])} days.", 'backlog_driver': f"The strongest diagnostic hypothesis is **{ctx['top_root']['hypothesis'].replace('_', ' ')}**. Evidence: {ctx['top_root']['evidence']} This is a triage hypothesis, not a causal conclusion.", 'group_waits': f"The highest P90 group is {ctx['top_group']['funding_route'].replace('_', ' ')} / {ctx['top_group']['service_group'].replace('_', ' ')}, with median {ctx['_fmt'](ctx['top_group']['median_referral_to_assessment_days'])} and P90 {ctx['_fmt'](ctx['top_group']['p90_referral_to_assessment_days'])} days across {int(ctx['top_group']['referrals'])} referrals.", 'stage_owner': f"The dominant stage is owned primarily by **{ctx['top_stage_owner']}**. I would verify timestamp semantics and weekly queue behaviour before assigning accountability or changing resources.", 'completion_change': f"Overall completed assessments equal {ctx['_pct'](ctx['completion'])} of accepted referrals in the full synthetic cohort. A period decline should first be separated into immature cohorts, segment mix and within-segment conversion before calling it a process failure.", 'open_cases': f"A broad synthetic count of referrals not yet at treatment start is {ctx['open_cases']:,}. The operational queue must apply stage, overdue and exclusion rules and must not be presented as clinical priority.", 'queue_policy': f"At equal capacity, {ctx['summary']['queue_policy_lowest_max_wait'].replace('_', ' ')} has the lowest maximum remaining wait. That does not make it universally fairest; the decision must state whether the objective is longest-wait reduction, readiness or group balance.", 'extra_clinic': f"Adding one synthetic assessment clinic changes end backlog from {ctx['_fmt'](ctx['baseline_scenario']['end_backlog'], 0)} to {ctx['_fmt'](ctx['extra_clinic']['end_backlog'], 0)}, avoiding {ctx['_fmt'](ctx['extra_clinic']['backlog_patients_avoided'], 0)} backlog patients at a 12-week cost proxy of £{ctx['_fmt'](ctx['extra_clinic']['horizon_cost_proxy_gbp'], 0)}."}
